import{_ as t,o as a,c as i,ao as s}from"./chunks/framework.B9--V88m.js";const u=JSON.parse('{"title":"CLI Reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/cli.md","filePath":"reference/cli.md","lastUpdated":1781447342000}'),n={name:"reference/cli.md"};function l(o,e,d,c,h,r){return a(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="CLI-Reference" tabindex="-1">CLI Reference <a class="header-anchor" href="#CLI-Reference" aria-label="Permalink to &quot;CLI Reference {#CLI-Reference}&quot;">​</a></h1><p>The <code>mexicah</code> command-line tool is a compiled Julia app (<code>juliac --output-exe</code>) for building MEX files without opening a Julia REPL.</p><h2 id="Building-the-CLI" tabindex="-1">Building the CLI <a class="header-anchor" href="#Building-the-CLI" aria-label="Permalink to &quot;Building the CLI {#Building-the-CLI}&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">juliac</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output-exe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mexicah</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --trim=safe</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app/cli.jl</span></span></code></pre></div><p>Place the resulting <code>mexicah</code> binary on your <code>PATH</code>.</p><h2 id="Commands" tabindex="-1">Commands <a class="header-anchor" href="#Commands" aria-label="Permalink to &quot;Commands {#Commands}&quot;">​</a></h2><h3 id="mexicah-compile" tabindex="-1"><code>mexicah compile</code> <a class="header-anchor" href="#mexicah-compile" aria-label="Permalink to &quot;`mexicah compile` {#mexicah-compile}&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mexicah compile &lt;package&gt; [options]</span></span></code></pre></div><p>Compile the selected <code>@mexfunction</code>s from <code>&lt;package&gt;</code> into one shared library plus a thin gateway MEX per function — the same as <code>build_shared_mex</code>, so the results share one Julia runtime and can be used together in a MATLAB session.</p><p><code>&lt;package&gt;</code> must be a <strong>loadable Julia package</strong> whose functions are annotated with <code>@mexfunction</code>. <code>juliac</code> compiles in a separate process and cannot see functions defined only in a script or the REPL.</p><h4 id="Options" tabindex="-1">Options <a class="header-anchor" href="#Options" aria-label="Permalink to &quot;Options {#Options}&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:right;">Option</th><th style="text-align:right;">Default</th><th style="text-align:right;">Description</th></tr></thead><tbody><tr><td style="text-align:right;"><code>--function &lt;names&gt;</code></td><td style="text-align:right;">—</td><td style="text-align:right;">Comma-separated function names to compile. Required unless <code>--all-exported</code>.</td></tr><tr><td style="text-align:right;"><code>--output &lt;dir&gt;</code></td><td style="text-align:right;"><code>./mex/</code></td><td style="text-align:right;">Output directory for the gateways, shared library, and bundle.</td></tr><tr><td style="text-align:right;"><code>--all-exported</code></td><td style="text-align:right;">off</td><td style="text-align:right;">Compile every function registered via <code>@mexfunction</code>.</td></tr><tr><td style="text-align:right;"><code>--no-trim</code></td><td style="text-align:right;">off</td><td style="text-align:right;">Disable <code>juliac --trim=safe</code>. Produces larger but more permissive binaries.</td></tr><tr><td style="text-align:right;"><code>--juliac &lt;path&gt;</code></td><td style="text-align:right;"><code>juliac</code></td><td style="text-align:right;">Path to the juliac binary.</td></tr></tbody></table><h4 id="Examples" tabindex="-1">Examples <a class="header-anchor" href="#Examples" aria-label="Permalink to &quot;Examples {#Examples}&quot;">​</a></h4><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Every @mexfunction-annotated function in the package</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mexicah</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MySolvers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all-exported</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./mex/</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Just a couple of them</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mexicah</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> MySolvers</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --function</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add_doubles,scale_rows</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --output</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./mex/</span></span></code></pre></div><h3 id="mexicah-help" tabindex="-1"><code>mexicah help</code> <a class="header-anchor" href="#mexicah-help" aria-label="Permalink to &quot;`mexicah help` {#mexicah-help}&quot;">​</a></h3><p>Print usage information.</p><h2 id="Functions-must-be-registered" tabindex="-1">Functions must be registered <a class="header-anchor" href="#Functions-must-be-registered" aria-label="Permalink to &quot;Functions must be registered {#Functions-must-be-registered}&quot;">​</a></h2><p>Only functions annotated with <code>@mexfunction</code> (or registered via <code>Mexicah._register_mex_export</code>) carry type signature metadata. The CLI reads this metadata to know what concrete types to use for argument marshaling.</p><p>If you need to compile an existing function without <code>@mexfunction</code>, use <code>build_mex</code> from the Julia API and pass <code>input_types</code> and <code>output_types</code> explicitly.</p>',19)])])}const g=t(n,[["render",l]]);export{u as __pageData,g as default};
